    "role": "agent",
    "message": "Perfect! Thanks for calling EzMedTech, Ben. Just to remind you, you have your appointment tomorrow at four thirty PM with Dr. Rakesh Kumar. Take care and have a wonderful day!"
  },
  {
    "role": "user",
    "message": "Yeah thanks."
  },
  {
    "role": "agent",
    "message": "You're welcome! Have a great day, Ben!"
  }
